SELECT n.*,
       COALESCE(s.read_status, 0) AS read_status,
       COALESCE(s.ack_status, 0) AS ack_status
FROM notification_record n
LEFT JOIN user_notification_state s
    ON n.id = s.notification_id AND s.user_id = #{userId}
WHERE n.expire_time > #{now}
  AND (n.broadcast = 1 OR s.user_id = #{userId})
ORDER BY n.create_time DESC
LIMIT #{pageSize} OFFSET (#{page} - 1) * #{pageSize}

SELECT COUNT(*)
FROM notification_record n
LEFT JOIN user_notification_state s
    ON n.id = s.notification_id AND s.user_id = #{userId}
WHERE n.expire_time > #{now}
  AND (n.broadcast = 1 OR s.user_id = #{userId})
